const { ethers } = require("ethers");

async function swapTokens(userPrivateKey, rpcProviderUrl, tokenAAddress, tokenBAddress, userAddress, dexContractAddress, amountIn, amountOutMin, swapDeadline) {
  const provider = new ethers.providers.JsonRpcProvider(rpcProviderUrl);
  const wallet = new ethers.Wallet(userPrivateKey, provider);

  const erc20Abi = [
    "function approve(address spender, uint256 amount) external returns (bool)",
    "function balanceOf(address owner) view returns (uint256)"
  ];

  const dexAbi = [
    "function swapExactTokensForTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) external returns (uint256[] memory amounts)"
  ];

  const tokenAContract = new ethers.Contract(tokenAAddress, erc20Abi, wallet);
  const tokenBContract = new ethers.Contract(tokenBAddress, erc20Abi, wallet);
  const dexContract = new ethers.Contract(dexContractAddress, dexAbi, wallet);

  // Approve maximum uint256 amount
  const maxUint256 = ethers.constants.MaxUint256;
  
  try {
    await tokenAContract.approve(dexContractAddress, maxUint256);
    console.log("Approval transaction for Token A sent.");

    const tokenABalance = await tokenAContract.balanceOf(userAddress);
    console.log(`Token A Balance: ${tokenABalance.toString()}`);

    const path = [tokenAAddress, tokenBAddress];
    
    const swapTx = await dexContract.swapExactTokensForTokens(
      amountIn,
      amountOutMin,
      path,
      userAddress,
      swapDeadline
    );

    console.log("Swap transaction sent:", swapTx.hash);
    
    await swapTx.wait();
    console.log("Swap transaction confirmed.");
    
    const tokenBBalance = await tokenBContract.balanceOf(userAddress);
    console.log(`Token B Balance: ${tokenBBalance.toString()}`);
  } catch (error) {
    console.error("An error occurred:", error);
  }
}

